#include <iostream>
#include <string>
#include <cmath>
#include <sstream>
#include <iomanip>

class Complex {
public:
    double real;
    double imag;

    Complex(double r = 0.0, double i = 0.0) : real(r), imag(i) {}

    friend std::ostream& operator<<(std::ostream& os, const Complex& c);
};

std::ostream& operator<<(std::ostream& os, const Complex& c) {
    std::stringstream ss;
    ss.precision(15);
    ss << std::fixed;

    ss << "(";
    bool real_printed = false;

    if (c.real != 0.0 || c.imag == 0.0) {
        ss << c.real;
        real_printed = true;
    }

    if (c.imag != 0.0) {
        if (real_printed) {
            if (c.imag > 0) {
                ss << " + ";
            } else {
                ss << " - ";
            }
            ss << std::abs(c.imag) << "i";
        } else {
            ss << c.imag << "i";
        }
    } else if (!real_printed) {
        ss << "0";
    }

    ss << ")";
    return os << ss.str();
}

int main() {
    std::cout.precision(15);
    std::cout << std::fixed;
    Complex c1(3, 5);
    Complex c2(3, -5);
    Complex c3(3, 0);
    Complex c4(0, 5);
    Complex c5(0, -5);
    Complex c6(0, 0);
    Complex c7(-3, 5);
    Complex c8(-3, -5);

    std::cout << c1 << std::endl;
    std::cout << c2 << std::endl;
    std::cout << c3 << std::endl;
    std::cout << c4 << std::endl;
    std::cout << c5 << std::endl;
    std::cout << c6 << std::endl;
    std::cout << c7 << std::endl;
    std::cout << c8 << std::endl;
    return 0;
}
